function getRegister($mac, $val)
{
    global $register_array;
    $ret = "";
    for ($i = 0; $i < count($register_array); $i++) {
        if ($register_array[$i][0] == encryptDecrypt($mac)) {
            $ret = $register_array[$i][$val];
            break;
        }
    }
    if ($ret == "") {
        if ($val == 1) {
            $ret = 419;
        } else {
            if ($val == 2) {
                $ret = 20501231;
            } else {
                if ($val == 3) {
                    $ret = 0;
                } else {
                    if ($val == 4) {
                        $ret = "DEMO VERSION2";
                    } else {
                        if ($val == 5) {
                            $ret = "Virdi TA";
                        } else {
                            if ($val == 6) {
                                $ret = "West Africa";
                            }
                        }
                    }
                }
            }
        }
    }
    return $ret;
}

